# 1. Cài isc-dhcp-server
sudo apt update
sudo apt install -y isc-dhcp-server tcpdump

# 2. Bật listen trên ens33
sudo nano /etc/default/isc-dhcp-server
#   INTERFACESv4="ens33"
#   INTERFACESv6=""

# 3. Cấu hình dhcpd.conf minimal (10 dòng)
sudo nano /etc/dhcp/dhcpd.conf
#   default-lease-time 120;
#   max-lease-time 300;
#   authoritative;
#   log-facility local7;
#   subnet 192.168.81.0 netmask 255.255.255.0 {
#     range 192.168.81.100 192.168.81.110;
#     option routers 192.168.81.10;
#     option domain-name-servers 8.8.8.8, 1.1.1.1;
#     option broadcast-address 192.168.81.255;
#   }

# 4. Verify syntax
sudo dhcpd -t -cf /etc/dhcp/dhcpd.conf

# 5. Restart + check
sudo systemctl restart isc-dhcp-server
sudo ss -ulnp | grep :67
